import * as React from "react";

import "./equipment-info.css";

export type EquipmentInfoRecord = {
  serial: string;
  assetNumber: string;
  healthScore: number;
  brand: string;
  model: string;
  hospital: string;
};

export type EquipmentInfoProps = {
  title: string;
  value: string;
};

export const EquipmentInfo = (props: EquipmentInfoProps) => {
  const { title, value } = props;
  return (
    <div>
      <div className="EquipmentInfoTitle">{title}</div>
      <div className="EquipmentInfoContent">{value}</div>
    </div>
  );
};
